// Verify webhook signature and processing
const validateWebhook = (req, res) => {
  const signature = req.headers['x-hub-signature-256'];
  const body = JSON.stringify(req.body);

  const expectedSignature = crypto
    .createHmac('sha256', WEBHOOK_VERIFY_TOKEN)
    .update(body)
    .digest('hex');

  if (signature !== `sha256=${expectedSignature}`) {
    console.error('Webhook signature validation failed');
    return false;
  }

  // Log delivery status updates
  req.body.entry?.forEach(entry => {
    entry.changes?.forEach(change => {
      if (change.field === 'messages') {
        change.value.statuses?.forEach(status => {
          console.log(`Message ${status.id}: ${status.status}`);
          if (status.status === 'failed') {
            console.error('Delivery failure:', status.errors);
          }
        });
      }
    });
  });

  return true;
};
```

