def analyze_spam_patterns():
    # Check message frequency per user
    user_message_counts = {}

    for message in recent_outbound_messages:
        user_id = message['to']
        timestamp = message['timestamp']

        if user_id not in user_message_counts:
            user_message_counts[user_id] = []
        user_message_counts[user_id].append(timestamp)

    # Identify users receiving too many messages
    spam_candidates = {
        user_id: len(timestamps) 
        for user_id, timestamps in user_message_counts.items()
        if len(timestamps) > MAX_MESSAGES_PER_HOUR
    }

    return spam_candidates
