### 2. Content Analysis
```javascript
// Check for repetitive or template abuse
const analyzeMessageContent = (messages) => {
  const contentFrequency = {};
  const templateUsage = {};

  messages.forEach(msg => {
    // Track identical message content
    const contentHash = crypto.createHash('md5')
      .update(msg.text || JSON.stringify(msg))
      .digest('hex');

    contentFrequency[contentHash] = (contentFrequency[contentHash] || 0) + 1;

    // Track template usage
    if (msg.template) {
      const templateKey = msg.template.name;
      templateUsage[templateKey] = (templateUsage[templateKey] || 0) + 1;
    }
  });

  return { contentFrequency, templateUsage };
};
```

## Delivery Failure Analysis

### 1. Error Code Classification
```python
def classify_delivery_errors(failed_messages):
    platform_errors = []
    application_errors = []

    for message in failed_messages:
        error_code = message.get('error_code')
        error_subcode = message.get('error_subcode')

        # Platform-level issues
        if error_code in [4, 10, 100]:  # Rate limiting, temporary issues
            platform_errors.append({
                'type': 'rate_limit_or_temporary',
                'message_id': message['id'],
                'error': message['error']
            })
        elif error_code == 131000:  # Generic WhatsApp error
            platform_errors.append({
                'type': 'whatsapp_platform',
                'message_id': message['id'],
                'error': message['error']
            })
        # Application-level issues
        elif error_code in [132000, 132001]:  # Parameter errors
            application_errors.append({
                'type': 'invalid_parameters',
                'message_id': message['id'],
                'error': message['error']
            })

    return platform_errors, application_errors
```

